// Extract and clean article text from HTML
const html = $input.first().json.data || '';
const rssItem = $('Merge All Feeds').first().json;

// Simple HTML text extractor
const text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&nbsp;/g, ' ')
  .replace(/\s{2,}/g, ' ')
  .trim();

// Skip if too short (paywalled or failed fetch)
if (text.length < 400) {
  console.log('SKIP: Too short, likely paywalled -', rssItem.title);
  return [];
}

return [{
  json: {
    source_url: rssItem.link || '',
    title: rssItem.title || 'Unknown',
    pub_date: rssItem.pubDate || new Date().toISOString(),
    article_text: text.substring(0, 14000)
  }
}];

