try {
  const raw = $input.first().json.candidates[0].content.parts[0].text;
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const gemini = JSON.parse(cleaned);

  // TRASH articles scoring below 6
  if (!gemini.score || gemini.score < 6) {
    console.log('TRASH (score ' + gemini.score + '):', $('Extract & Clean Text').first().json.title);
    return [];
  }

  const articleData = $('Extract & Clean Text').first().json;

  return [{
    json: {
      ...articleData,
      quality_score: gemini.score,
      category: gemini.category || 'Misc',
      vulnerability_type: gemini.vulnerability_type || 'Logic Flaw',
      severity: gemini.severity || 'Medium',
      tools_mentioned: gemini.tools_mentioned || [],
      one_line_summary: gemini.one_line_summary || ''
    }
  }];
} catch(e) {
  console.log('Gemini parse error:', e.message);
  return [];
}

