try {
  const groqRaw = $input.first().json.choices[0].message.content;
  const groqCleaned = groqRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const notes = JSON.parse(groqCleaned);

  const d = $('Filter — Score < 6 = Trash').first().json;
  const today = new Date().toISOString().split('T')[0];

  // Build safe filename for Obsidian
  const safeTitle = d.title
    .replace(/[^a-zA-Z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .toLowerCase()
    .substring(0, 70);
  const filename = `${today}-${safeTitle}`;

  const toolTags = (d.tools_mentioned || []).map(t => t.replace(/\s+/g, '-').toLowerCase()).join(' ');
  const obsidianContent = `---
title: "${d.title.replace(/"/g, "'")}"
category: ${d.category}
vulnerability_type: ${d.vulnerability_type}
severity: ${d.severity}
quality_score: ${d.quality_score}
source: ${d.source_url}
date_added: ${today}
status: new
tags: [security, ${d.category.toLowerCase().replace(/[\s\/]/g, '-')}, ${d.vulnerability_type.toLowerCase().replace(/\s+/g, '-')}, ${toolTags}]
---

# ${d.title}

> **Category:** ${d.category} | **Vuln:** ${d.vulnerability_type} | **Severity:** ${d.severity} | **Quality:** ${d.quality_score}/10
> **Source:** [Original Article](${d.source_url})
> **Summary:** ${d.one_line_summary}

---

## 🔍 Root Cause

${notes.root_cause}

---

## 🎯 Exploitation Walkthrough

${notes.exploitation_walkthrough}

---

## 💣 Payloads & Commands

\`\`\`
${notes.payloads_and_commands}
\`\`\`

---

## 💥 Impact

${notes.impact}

---

## 🔗 Chaining Opportunities

${notes.chaining_opportunities}

---

## 🔎 Detection & Hunting

${notes.detection_and_hunting}

---

## 🛡️ Remediation

${notes.remediation}

---

## ⚡ Key Takeaways

${notes.key_takeaways}
`;

  return [{
    json: {
      // Dashboard + Sheets fields
      date_added: today,
      title: d.title,
      category: d.category,
      vulnerability_type: d.vulnerability_type,
      severity: d.severity,
      quality_score: d.quality_score,
      tools_used: d.tools_mentioned || [],
      source_url: d.source_url,
      one_line_summary: d.one_line_summary || '',
      // Full Groq fields (for dashboard API)
      root_cause: notes.root_cause || '',
      exploitation_walkthrough: notes.exploitation_walkthrough || '',
      payloads_and_commands: notes.payloads_and_commands || '',
      impact: notes.impact || '',
      chaining_opportunities: notes.chaining_opportunities || '',
      detection_and_hunting: notes.detection_and_hunting || '',
      remediation: notes.remediation || '',
      key_takeaways: notes.key_takeaways || '',
      status: 'new',
      // Obsidian
      obsidian_filename: filename,
      obsidian_content: obsidianContent
    }
  }];
} catch(e) {
  console.log('Groq parse error:', e.message);
  return [];
}

// Write markdown file to Obsidian vault
const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const vaultPath = process.env.OBSIDIAN_VAULT || '/home/pavan/SecurityKB';

// Create subfolder by category
const categoryFolder = data.category.replace(/[^a-zA-Z0-9\s]/g, '').replace(/\s+/g, '-');
const folderPath = path.join(vaultPath, categoryFolder);
fs.mkdirSync(folderPath, { recursive: true });

// Write the markdown file
const filepath = path.join(folderPath, `${data.obsidian_filename}.md`);
fs.writeFileSync(filepath, data.obsidian_content, 'utf8');

console.log('Written to Obsidian:', filepath);

return [{ json: { ...data, obsidian_file_path: filepath } }];
